def _batch_values(
    values: cabc.Iterable[V], batch_size: int
) -> cabc.Iterator[tuple[V, ...]]:
    """Group ``values`` into chunks of at most ``batch_size`` items,
    including a final, possibly shorter, chunk.
    """
    if batch_size < 1:
        chunk = tuple(values)
        if chunk:
            yield chunk
        return

    iterator = iter(values)

    while True:
        chunk = tuple(itertools.islice(iterator, batch_size))

        if not chunk:
            return

        yield chunk

